/**
 * Runs Dijkstra's algorithm from a single source node to find shortest paths to all other nodes.
 * @param n The number of nodes.
 * @param adj The adjacency list representation of the graph.
 * @param startNode The source node.
 * @return An array of minimum distances from startNode to all other nodes.
 */
fun dijkstra(n: Int, adj: Array<MutableList<Edge>>, startNode: Int): LongArray {
    val INF = Long.MAX_VALUE
    val dist = LongArray(n) { INF }
    dist[startNode] = 0L

    val pq = PriorityQueue<State>()
    pq.add(State(startNode, 0L))

    while (pq.isNotEmpty()) {
        val current = pq.poll()
        val u = current.node
        val d = current.distance

        if (d > dist[u]) continue

        for (edge in adj[u]) {
            val v = edge.to
            val weight = edge.weight
            val newDist = d + weight

            if (newDist < dist[v]) {
                dist[v] = newDist
                pq.add(State(v, newDist))
            }
        }
    }
    return dist
}


fun solve(n: Long, prices: Array<Long>, roads: Array<Array<Long>>): Array<Long> {
    val N = n.toInt()
    val INF = Long.MAX_VALUE / 2 // Use a safe infinity value

    // 1. Build Graphs

    // G_empty: Weights are 'cost'
    val adjEmpty = Array(N) { mutableListOf<Edge>() }
    // G_taxed: Weights are 'cost * tax'
    val adjTaxed = Array(N) { mutableListOf<Edge>() }

    for (road in roads) {
        val u = road[0].toInt()
        val v = road[1].toInt()
        val cost = road[2]
        val tax = road[3]

        // Graph Empty
        adjEmpty[u].add(Edge(v, cost))
        adjEmpty[v].add(Edge(u, cost))

        // Graph Taxed
        val taxedCost = cost * tax
        adjTaxed[u].add(Edge(v, taxedCost))
        adjTaxed[v].add(Edge(u, taxedCost))
    }

    // 2. Run Dijkstra N times for both graphs to get All-Pairs Shortest Paths (APSP)

    // DE[i][j]: Shortest path from i to j without apples
    val DE = Array(N) { LongArray(N) { INF } }
    // DT[i][j]: Shortest path from i to j with apples
    val DT = Array(N) { LongArray(N) { INF } }

    for (i in 0 until N) {
        // Calculate D_empty starting from i
        val distEmpty = dijkstra(N, adjEmpty, i)
        for (j in 0 until N) {
            DE[i][j] = distEmpty[j]
        }

