        // Option 1: Buy directly at i
        var minCost = prices[i]

        // Option 2: Buy at j and return to i
        for (j in 0 until N) {
            if (i == j) continue

            // Cost = D_empty(i -> j) + prices[j] + D_taxed(j -> i)

            val dist_i_j_empty = DE[i][j]
            val dist_j_i_taxed = DT[j][i] // Note: DT[j][i] is the cost from j back to i

            if (dist_i_j_empty != INF && dist_j_i_taxed != INF) {
                // Check for overflow before adding prices[j]
                // Since INF is half of MAX_VALUE, the sum should be safe if we ensure all components are less than INF.
                val totalCost = dist_i_j_empty + prices[j] + dist_j_i_taxed
                minCost = min(minCost, totalCost)
            }
        }
        ans[i] = minCost
    }

    return ans
}

