import java.util.PriorityQueue

fun solve(n: Long, prices: Array<Long>, roads: Array<Array<Long>>): Array<Long> {
    val N = n.toInt()
    val INF = Long.MAX_VALUE / 2 // Use half MAX_VALUE to prevent overflow during addition

    // 1. Build Adjacency Lists
    // AdjE[u] stores pairs (v, cost) for empty travel
    val adjE = List(N) { mutableListOf<Pair<Int, Long>>() }
    // AdjL[u] stores pairs (v, cost * tax) for loaded travel
    val adjL = List(N) { mutableListOf<Pair<Int, Long>>() }

    for (road in roads) {
        val u = road[0].toInt()
        val v = road[1].toInt()
        val cost = road[2]
        val tax = road[3]

        // Empty Travel (Cost = C)
        adjE[u].add(Pair(v, cost))
        adjE[v].add(Pair(u, cost))

        // Loaded Travel (Cost = C * T)
        val loadedCost = cost * tax
        adjL[u].add(Pair(v, loadedCost))
        adjL[v].add(Pair(u, loadedCost))
    }

    // Helper function for Dijkstra's algorithm
    fun dijkstra(adj: List<MutableList<Pair<Int, Long>>>, startNode: Int): LongArray {
        val dist = LongArray(N) { INF }
        dist[startNode] = 0L

        // PriorityQueue stores Pair(distance, node)
        val pq = PriorityQueue<Pair<Long, Int>>(compareBy { it.first })
        pq.add(Pair(0L, startNode))

        while (pq.isNotEmpty()) {
            val (d, u) = pq.poll()

            if (d > dist[u]) continue

            for ((v, weight) in adj[u]) {
                val newDist = dist[u] + weight
                if (newDist < dist[v]) {
                    dist[v] = newDist
                    pq.add(Pair(newDist, v))
                }
            }
        }
        return dist
    }

    // 2. Compute Shortest Paths Matrices

    // D_E[i][j]: Shortest path i -> j (Empty)
    val DE = Array(N) { LongArray(N) }
    for (i in 0 until N) {
        DE[i] = dijkstra(adjE, i)
    }

    // D_L[j][i]: Shortest path j -> i (Loaded)
    // We run Dijkstra from j on G_L to get distances to all other nodes i.
    val DL = Array(N) { LongArray(N) }
    for (j in 0 until N) {
        val distancesFromJ = dijkstra(adjL, j)
        // We want DL[j][i] = distance from j to i
        for (i in 0 until N) {
            DL[j][i] = distancesFromJ[i]
        }
    }

    // 3. Calculate Final Answer
